CREATE TABLE IF NOT EXISTS tb_salary_scales (salary_scale_id INT NOT NULL AUTO_INCREMENT PRIMARY KEY,scale_code VARCHAR(30) NOT NULL UNIQUE,description VARCHAR(160) DEFAULT NULL,sort_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME DEFAULT NULL,KEY idx_salary_scale_active(is_active,sort_order)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
